import{_ as i,c as o,o as n,a5 as t,j as e}from"./chunks/framework.Dtwt352Q.js";const u=JSON.parse('{"title":"v1.1.57: Major Desktop Optimization","description":"","frontmatter":{},"headers":[],"relativePath":"en/changelog/v1.1.57.md","filePath":"en/changelog/v1.1.57.md","lastUpdated":1772014034000}'),r={name:"en/changelog/v1.1.57.md"};function s(l,a,d,p,h,c){return n(),o("div",null,[...a[0]||(a[0]=[t('<h1 id="v1-1-57-major-desktop-optimization" tabindex="-1">v1.1.57: Major Desktop Optimization <a class="header-anchor" href="#v1-1-57-major-desktop-optimization" aria-label="Permalink to “v1.1.57: Major Desktop Optimization”">​</a></h1><p><strong>Release Date</strong>: February 11, 2026</p><hr><h2 id="one-sentence-summary" tabindex="-1">One-Sentence Summary <a class="header-anchor" href="#one-sentence-summary" aria-label="Permalink to “One-Sentence Summary”">​</a></h2><p>This update <strong>significantly optimizes desktop app experience</strong>, fixes terminal copy/paste, Windows adaptation, Wayland support issues, and improves context compression reliability.</p><hr><h2 id="new-feature-wsl-backend-mode" tabindex="-1">New Feature: WSL Backend Mode <a class="header-anchor" href="#new-feature-wsl-backend-mode" aria-label="Permalink to “New Feature: WSL Backend Mode”">​</a></h2><h3 id="what-s-updated" tabindex="-1">What&#39;s Updated? <a class="header-anchor" href="#what-s-updated" aria-label="Permalink to “What&#39;s Updated?”">​</a></h3><p>Desktop OpenCode now supports <strong>WSL backend mode</strong>, allowing OpenCode to run through WSL on Windows for better compatibility.</p><h3 id="what-is-wsl-backend-mode" tabindex="-1">What is WSL Backend Mode? <a class="header-anchor" href="#what-is-wsl-backend-mode" aria-label="Permalink to “What is WSL Backend Mode?”">​</a></h3><p>If you use WSL (Windows Subsystem for Linux) on Windows, you can have desktop OpenCode run in the WSL environment instead of directly on Windows.</p><h3 id="what-are-the-benefits" tabindex="-1">What are the Benefits? <a class="header-anchor" href="#what-are-the-benefits" aria-label="Permalink to “What are the Benefits?”">​</a></h3><ul><li>Better Linux toolchain compatibility</li><li>Filesystem behavior consistent with Linux</li><li>Avoid some Windows-specific issues</li></ul><hr><h2 id="improvement-more-reliable-context-compression" tabindex="-1">Improvement: More Reliable Context Compression <a class="header-anchor" href="#improvement-more-reliable-context-compression" aria-label="Permalink to “Improvement: More Reliable Context Compression”">​</a></h2><h3 id="previous-issue" tabindex="-1">Previous Issue <a class="header-anchor" href="#previous-issue" aria-label="Permalink to “Previous Issue”">​</a></h3><p>In long conversations, OpenCode automatically compresses context to save tokens. But sometimes compression wasn&#39;t reliable enough, potentially causing information loss.</p><h3 id="current-status" tabindex="-1">Current Status <a class="header-anchor" href="#current-status" aria-label="Permalink to “Current Status”">​</a></h3><ul><li>Added reserved token buffer, leaving enough space for input window compression</li><li>Added more context overflow handling scenarios</li><li>Removed over-correction situations</li></ul><hr><h2 id="improvement-tui-sidebar-defaults-to-auto" tabindex="-1">Improvement: TUI Sidebar Defaults to Auto <a class="header-anchor" href="#improvement-tui-sidebar-defaults-to-auto" aria-label="Permalink to “Improvement: TUI Sidebar Defaults to Auto”">​</a></h2><h3 id="change" tabindex="-1">Change <a class="header-anchor" href="#change" aria-label="Permalink to “Change”">​</a></h3><p>TUI (terminal interface) session sidebar now defaults to &quot;auto&quot; mode, automatically showing or hiding based on terminal width.</p><hr><h2 id="bug-fix-multiple-desktop-improvements" tabindex="-1">Bug Fix: Multiple Desktop Improvements <a class="header-anchor" href="#bug-fix-multiple-desktop-improvements" aria-label="Permalink to “Bug Fix: Multiple Desktop Improvements”">​</a></h2><h3 id="terminal-copy-paste" tabindex="-1">Terminal Copy/Paste <a class="header-anchor" href="#terminal-copy-paste" aria-label="Permalink to “Terminal Copy/Paste”">​</a></h3><p>Previously desktop app terminal copy/paste had issues, now fixed.</p><h3 id="windows-app-adaptation" tabindex="-1">Windows App Adaptation <a class="header-anchor" href="#windows-app-adaptation" aria-label="Permalink to “Windows App Adaptation”">​</a></h3><ul><li>Improved Windows app resolution detection</li><li>Optimized UI loading state</li><li>Fixed copy path button style</li></ul><h3 id="wayland-support" tabindex="-1">Wayland Support <a class="header-anchor" href="#wayland-support" aria-label="Permalink to “Wayland Support”">​</a></h3><p>Desktop app now reads Wayland preference from config, better supporting Linux Wayland display server.</p><hr><h2 id="should-you-upgrade" tabindex="-1">Should You Upgrade? <a class="header-anchor" href="#should-you-upgrade" aria-label="Permalink to “Should You Upgrade?”">​</a></h2><table tabindex="0"><thead><tr><th>Situation</th><th>Recommendation</th></tr></thead><tbody><tr><td>Using desktop version</td><td>✅ Upgrade</td></tr><tr><td>Windows users</td><td>✅ Highly Recommended</td></tr><tr><td>Only using terminal version</td><td>Can wait for next time</td></tr></tbody></table><p><strong>Upgrade Command</strong>:</p>',35),e("div",{class:"language-bash"},[e("button",{title:"Copy Code",class:"copy"}),e("span",{class:"lang"},"bash"),e("pre",null,[e("code",{"v-pre":""},"opencode upgrade")])],-1),t('<hr><h2 id="technical-details-skippable" tabindex="-1">Technical Details (Skippable) <a class="header-anchor" href="#technical-details-skippable" aria-label="Permalink to “Technical Details (Skippable)”">​</a></h2><details><summary>Click to expand full update list</summary><h3 id="core" tabindex="-1">Core <a class="header-anchor" href="#core" aria-label="Permalink to “Core”">​</a></h3><ul><li>Add more context overflow handling scenarios, remove over-correction</li><li>Ensure compression is more reliable, add reserved token buffer</li><li>Improve /review prompt, more clearly detect behavior changes</li><li>Improve Amazon Bedrock check, support container credentials</li></ul><h3 id="tui" tabindex="-1">TUI <a class="header-anchor" href="#tui" aria-label="Permalink to “TUI”">​</a></h3><ul><li>Session sidebar defaults to auto mode</li></ul><h3 id="desktop" tabindex="-1">Desktop <a class="header-anchor" href="#desktop" aria-label="Permalink to “Desktop”">​</a></h3><ul><li>Fix terminal copy/paste functionality</li><li>Fix copy path button style</li><li>Use tracing for logging</li><li>Enhance Windows app resolution and UI loading state</li><li>Improve desktop app server startup resilience</li><li>Read Wayland preference from config</li><li>Add WSL backend mode</li></ul><h3 id="sdk" tabindex="-1">SDK <a class="header-anchor" href="#sdk" aria-label="Permalink to “SDK”">​</a></h3><ul><li>Encode non-ASCII directory paths in v1 SDK HTTP headers</li></ul><h3 id="community-contributions" tabindex="-1">Community Contributions <a class="header-anchor" href="#community-contributions" aria-label="Permalink to “Community Contributions”">​</a></h3><ul><li>@OpeOginni: Improve Amazon Bedrock check to support container credentials</li><li>@Brendonovich: Add WSL backend mode, Wayland preference, tracing logs</li><li>@neriousy: Enhance Windows app resolution and UI loading state</li><li>@MrMushrooooom: Fix non-ASCII directory path encoding</li><li>@ariane-emory: Remove migration to 1.0 documentation</li></ul></details><hr><p><a href="./">← Back to Changelog</a></p>',5)])])}const b=i(r,[["render",s]]);export{u as __pageData,b as default};
